/*【▪一剪梅▪】作者：易碎蝶*/
/*🍃←这个是可以调整的部分，以及用了【这个符号】*/

/* ====== 全局字体设置 ====== */
@import url("https://fontsapi.zeoseven.com/467/main/result.css");

body {
    font-family: "NanoOldSong-A";
    font-weight: normal;
}
/*———————— 移动端顶栏背景 ————————*/
#top-bar {
    position: fixed !important;  /* 改为固定定位适配移动端 */
    overflow: visible !important;
    background: none !important;
    border: 0 !important;
    box-shadow: none !important;
    pointer-events: none;
    width: 100vw;  /* 全屏宽度 */
    height: 77px;  /* 适合移动端的顶部高度 */
    top: 0;
    left: 0;
}

#top-bar::before {
    content: "";
    position: fixed;
    background: url("https://i.postimg.cc/XJj7nSzJ/Image-2151101182294215.png") no-repeat center / cover;  /* 使用cover适配屏幕 */

    /* 移动端适配定位 */
    top: 0px;
    left: 0px;
    right: 0px;
    bottom: 20px;

    /* 层级控制 */
    z-index: 5;
    pointer-events: auto;

    /* 移除动画相关属性 */
    transform: none !important;
    animation: none !important;
}

/* 燕子从左侧飞到右侧的动画 */
@keyframes flyAcross {
  0% { left: -150px; } /* 起始位置：屏幕左侧外 */
  100% { left: 100%; }  /* 结束位置：屏幕右侧外 */
}

/* 应用到顶栏装饰层 */
#top-bar::after {
  animation: flyAcross 10s linear infinite; /* 匀速直线飞行 */
  /* 调整定位方式 */
  left: -150px; /* 初始位置设为屏幕外 */
  top: -25px;   /* 保持原有垂直位置 */
  right: auto;  /* 清除原有右侧定位 */
  /* 保留其他样式 */
  content: "";
  position: fixed;
  background: url("https://i.postimg.cc/zfSGmXp6/Image-2151103270157677.png") no-repeat center / contain;
  width: 150px;
  height: 150px;
  z-index: 6;
  pointer-events: none;
}


/* —————面板背景图———— */
.drawer-content {
  background-image: url('https://i.postimg.cc/HscWYtBQ/Image-2151088612959137.png'); /* 示例图片URL */
  background-size: cover; /* 图片覆盖整个元素 */
  background-position: center; /* 图片居中显示 */
  background-repeat: no-repeat; /* 图片不重复 */
  background-attachment: fixed; /* 固定背景图片 */
}

/*——————滑块——————*/

input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    appearance: none;
    width: 50px;
    height: 40px;
    background: transparent url('https://i.postimg.cc/76cxyG8H/Image-2152333183881135.png') center/cover no-repeat;
    border: none;
    border-radius: 0;
    box-shadow: none;
    cursor: ew-resize;
    position: relative;
    z-index: 1;
}

/*——————最新消息箭头图标替换——————*/
/* 隐藏原有字体图标 */
.fa-chevron-right:before,
.fa-chevron-left:before {
  content: "" !important;
}

/* 左箭头图片容器 */
.fa-chevron-left {
  display: inline-block;
  width: 90px; /* 图片宽度 */
  height: 130px; /* 图片高度 */
  background: url('https://i.postimg.cc/CMvdL5YV/Image-2151112991796370.png') center/contain no-repeat;
  /* ↑ 替换为您的左箭头图片链接 ↑ */
}

/* 右箭头图片容器 */
.fa-chevron-right {
  display: inline-block;
  width: 160px; /* 图片宽度 */
  height: 150px; /* 图片高度 */
  background: url('https://i.postimg.cc/cJNL587f/Image-2151105355367831.png') center/contain no-repeat;
  /* ↑ 替换为您的右箭头图片链接 ↑ */
}

.swipes-counter {
  color: var(--SmartThemeBodyColor);
  font-size: 10px;
  /* 位置调整 */
  margin: var(--counter-vertical, 0) var(--counter-horizonta, 0); /* 垂直 水平 */
  /* 或使用绝对定位 */
  /* position: relative;
  left: var(--counter-left, 0);
  top: var(--counter-top, 0); */

  padding: 0 90px;
  z-index: 3;
  font-family: var(--mainFontFamily);
  font-weight: 440;
  align-self: center;
  min-width: 0px;
  display: flex;
  justify-content: center;
  margin-bottom: var(--swipeCounterMargin);
  height: var(--swipeCounterHeight);
}

.fa-arrow-right:before {
    display: none !important;
}

/*——————装饰层——————*/
/* /* ==============================================
 * 1. 🍃装饰层模块
 * ==============================================*/
/* 🍃上层装饰层 - 位于气泡上方 */
.mes::before {
  content: "";
  position: absolute;
  top: -58px; /* 上层装饰层【上下】(负值表示向上) */
  left: 0px; /* 上层装饰层【左右】 */
  width: 330px; /* 调整上层装饰层的【宽度/大小】 */
  height: 437px; /* 调整上层装饰层的【高度/大小】 */
  background-image: url('https://i.postimg.cc/Jnp7n6fQ/Image-2151096147181599.png'); /* 替换为你的图片链接 - 上层装饰层图片 */
  background-size: contain; /* 图片适应容器尺寸 */
  background-repeat: no-repeat; /* 不重复显示图片 */
  z-index: -2; /* 确保在气泡上方 */
  pointer-events: none; /* 避免阻挡鼠标事件 */
}



/* 🍃下层装饰层 - 位于气泡下方，跟随气泡尾部移动 */
.mes::after {
  content: "";
  position: absolute;
  bottom: -75px; /* 下层装饰层【上下】(负值表示向下) */
  right: -0px; /* 下层装饰层【左右】 */
  width: 330px; /* 调整下层装饰层的【宽度/大小】 */
  height: 266px; /* 调整下层装饰层的【高度/大小】 */
  background-image: url('https://i.postimg.cc/v8SHwKLY/Image-2151093713095753.png'); /* 替换为你的图片链接 - 下层装饰层图片 */
  background-size: contain; /* 图片适应容器尺寸 */
  background-repeat: no-repeat; /* 不重复显示图片 */
  z-index: 1; /* 确保在气泡上方 */
  pointer-events: none; /* 避免阻挡鼠标事件 */
}

/*——————🍃文本边距调整——————*/
/* 消息文本容器（可独立调整上下左右边距） */
.mes_text, 
.mes_reasoning {
    /* 基础样式 */
    font-weight: 500;
    line-height: calc(var(--mainFontSize) + .5rem);
    text-align: left; /* 文本左对齐 */
    overflow-wrap: anywhere;

    /* 🍃可独立调整的边距系统 */

    --top-padding:0rem; /* 气泡顶部留白 */
    --bottom-padding: 10rem; /* 气泡底部留白 */
    --left-padding: 0.2rem; /* 气泡左边距 */
    --right-padding: 0.8rem; /* 气泡右边距 */

    padding-top: var(--top-padding);
    padding-bottom: var(--bottom-padding);
    padding-left: var(--left-padding);
    padding-right: var(--right-padding);

    /* 最大宽度控制 */
    max-width: 700%;
    margin: 0; /* 清除默认外边距 */

    /* 气泡视觉相关样式（可根据UI需求扩展） */
    /* background-color: #f0f0f0; */
    /* border-radius: 19px; */
}




/*——————气泡设置——————*/

/* ==============================================
 * 1.🍃 气泡容器模块
 * ==============================================*/
.mes {
  z-index: -3;
  max-width: 330px;/*【🍃宽度】*/
  width: 400%;/*【🍃宽度，一般调整第一个就行，没效果再调整这个】*/
  margin: 120px auto 50px;/*【AI和用户的气泡距离】*/
  border-radius: 0px;
  /* 移除渐变背景和阴影 */
  background: url('https://i.postimg.cc/GtNcPBh8/Image-2151090920996061.png') repeat-y; /* 添加重复方向 */
  background-size: 100% auto; /* 保持宽度适配 */
  background-attachment: local; /* 确保滚动时背景同步 */
  transition: transform 0.2s ease; /* 移除阴影过渡 */
  transform-origin: top center;
  position: relative;
  overflow: visible;
  box-shadow: none !important; /* 强制移除所有阴影 */
}

/* ==============================================
 * 头像装饰框修复版 (确保图片显示)
 * ============================================== */
/* 1. 确保头像容器有尺寸 */
.mesAvatarWrapper {
  position: absolute;
  top: -147px;
  left: 48.9%;
  transform: translateX(-50%);
  z-index: -10;

  /* 【新增】必须设置宽高 */
  width: 70px;  /* 头像宽度 */
  height: 70px; /* 头像高度 */
  overflow: visible; /* 允许装饰框超出 */
}

/* 2. 🍃装饰框核心样式 */
.mesAvatarWrapper::after {
  content: "";
  position: absolute;
  top: 130%;/* 【上下】 */
  left: 255%;/* 【左右】 */
  width: 540%;  /* 【框比头像大15%】 */
  height: 300%; /* 【框比头像高15%】 */

  /* 【修复关键】必须设置display */
  display: block; /* 或 inline-block */

  /* 【修复关键】确保背景图加载 */
  background-image: url('https://i.postimg.cc/zvt2QW97/Image-2154268168935327.png');
  background-size: 100% 100%; /* 完全覆盖 */
  background-repeat: no-repeat;
  background-position: center;

  transform: translate(-50%, -50%);
  z-index: 3; /* 高于头像 */

  /* 调试辅助线 */
  /* border: 1px solid red; */
}

/* 3. 确保头像图片在装饰框下方 */
.mesAvatarWrapper img {
  position: relative;
  z-index: -10; /* 低于装饰框的20 */
}

/* ==============================================
 * 2. 🍃头像容器模块
 * ============================================== */
.mesAvatarWrapper {
  position: absolute;
  top: -40px;           /* 【控制头像在气泡上方的位置】 */
  left: 14%;            /* 【调整头像左右】 */
  transform: translateX(-50%);
  z-index: -1;
}

/* ==============================================
 * 3. 头像图像模块（可自定义形状）
 * ============================================== */
.mesAvatarWrapper .avatar {
  /* 🍃基础尺寸 - 可自定义修改 */
  width: 180px;           /* 头像宽度 */
  height: 120px;          /* 头像高度 */

  /* 形状控制 - 默认圆形 */
  border-radius: 50%;    /* 圆形（50%），可修改为不同值创建椭圆或圆角矩形 */

  /* 外观样式 */
  overflow: hidden;
  border: 0px solid #fff;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0);
  transition: all 0.3s ease;

  /* 旋转效果 */
  transform: rotate(-0deg); /* 顺时针旋转 */
}

.mesAvatarWrapper .avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

/* ==============================================
 * 4. 🍃楼层显示
 * ============================================== */
.mes .mesIDDisplay {

    position: fixed;  
    top: 200;           
    left: 27%;        /* 【楼层左右】 */
    transform: translateX(-50%); 
    z-index: 999;    
    margin-top: 28px; /* 【楼层上下】 */

    /* 简约样式 */
    padding: 2px 12px;
    background: rgba(255, 255, 255, 0.0); /* 【这里可以填楼层显示的背景色，最后一个数字区调整透明度】 */
    border-radius: 4px;
    box-shadow: 90 2px px rgba(0, 0, 0, 0.1);

    /* 保留原有样式 */
    z-index: 2;
    cursor: default;
    opacity: 0.7;
    font-size: calc(var(--mainFontSize) * 0.8);
    font-weight: 300;
    color: #191919; /* 【调整楼层显示的颜色】 */
}

/* 其他元素保持原有样式 */
.mes .mes_timer, .mes .tokenCounterDisplay {
    cursor: default;
    opacity: 0.7;
    font-size: calc(var(--mainFontSize) * 0.9);
    font-weight: 600;
    text-align: center;
}
/* ==============================================
 * 5. 🍃基础信息位置调整【时间戳等】
 * ============================================== */
/* 消息块容器 */
.mes_block {
  position: relative;
  padding-top: 96px; /* 保持顶部留白 */
  overflow: visible; /* 确保子元素不被裁剪 */
}

/* 角色名称 */
.mes_block .ch_name {
  position: relative;
  top: 2; /* 修正偏移量，避免过高 */
  left: 220px;/* 正值向右 */
  max-width: calc(100% - 105px); /* 保持宽度限制 */
  min-height: 77px;
  z-index: 10; /* 降低层级，确保不覆盖按钮 */
}

/* 时间戳 */
.timestamp {
  position: relative;
  position: absolute; /* 改为绝对定位 */
  top: 29px;/* 正值向下 */
  left: -80px;/* 正值向左 */
}

/* 编辑按钮 */
.mes_buttons {
  position: relative;
  top: 23px;/* 正值向下 */
  left: -125px;/* 正值向右 */
  z-index: 30; /* 提高层级，确保按钮可点击 */
}


.mes_edit_buttons {
    display: none;
    flex-direction: row;
    column-gap: 5px;
    float: right;
    cursor: pointer;
    padding-bottom: 5px;
    filter: drop-shadow(0px 0px 0px black);
    transition: 0.3s ease-in-out;

    /* 垂直位置控制 */
    position: relative;       /* 确保定位生效 */
    top: 10px;              /* 负数上移 | 正数下移 | 单位可用px/rem/vh等 */

    /* 水平位置控制 */
    right: 130px;            /* 负数右移 | 正数左移 | 单位可用px/rem/vw等 */
}

/* ==============================================
 * 🕒 计时器 & 🔤 字符计数显示组件
 * ============================================== */

.mes {
  position: relative; /* 创建定位上下文 */
}

/* 通用样式 */
.mes .mes_timer,
.mes .tokenCounterDisplay {
  position: fixed; /* 使用固定定位确保不被遮挡 */
  z-index: 2147483647; /* 最高层级 (32位整数最大值) */
  cursor: default;
  opacity: 0.5;
  font-size: calc(var(--mainFontSize) * 0.8);
  font-weight: 400;
  text-align: center;
  padding: 0px 0px;
  border-radius: 0px;
  background: rgba(30, 30, 30, 0.0); /* 半透明白色背景 */
  backdrop-filter: blur(0px); /* 毛玻璃效果 */
  box-shadow: 0 2px 8px rgba(0,0,0,0.0);

  /* 默认位置 - 顶部居中 */
  top: 240px;
  left: 50%;
  transform: translateX(-50%);

  /* 颜色变量 - 便于单独修改 */
  --timer-color: #191919;
  --counter-color: #191919;
}

/* 单独控制计时器 */
.mes .mes_timer {
  z-index: 2;
  /* 位置调整 */
  top: var(--timer-top, 60px);  /* 【🍃计时器上下】 */
  left: var(--timer-left, 350%);/*【🍃计时器左右】*/
  transform: translateX(var(--timer-translate, -50%));

  /* 颜色控制 */
  color: var(--timer-color, #191919);
}

/* 单独控制字符计数 */
.mes .tokenCounterDisplay {
  z-index: 2;
  /* 位置调整 */
  top: var(--counter-top, 8px); /* 【🍃字符上下】 */
  left: var(--counter-left, 280%);/* 【🍃字符左右】 */
  transform: translateX(var(--counter-translate, -0%));

  /* 颜色控制 */
  color: var(--counter-color, #191919);
}
/* ==============================================
 * 🧠 外显思维链位置与颜色调整
 * ============================================== */
.mes_reasoning_header {
  z-index: 3;
  /* 定位控制 */
  position: absolute;
  z-index: 9999;
  top: -49px;       /* 【🍃垂直位置】 */
  left: 10%;        /* 【🍃水平位置】 */
  transform: translateX(-50%);
cursor: pointer;
user-select: none;
font-size: calc(var(--mainFontSize) * 0.85);
opacity: 0.9;
transition: all 0.3s ease;

padding: 4px 10px;
background: #ffffff;  /* 纯白基底 - 日间模式 */
border-radius: 6px;
box-shadow: 0 2px 4px rgba(97, 59, 59, 0.15);  /* 浅棕投影 - 古风纸质感 */
border: 1px solid #613B3B;  /* 梅枝棕描边 - 核心色调 */

position: relative;
}
/* 双重描边效果 - 梅韵版 */
.mes_reasoning_header:before {
  border: 1px solid #EEEEEE;  /* 宣纸白描边 - 模拟古籍裱边 */
}
.mes_reasoning_header:after {
  border: 1px solid #613B3B;  /* 外圈梅枝棕描边 - 强化轮廓 */
}

/* 悬停效果 - 浅灰过渡 */
.mes_reasoning_header:hover {
  opacity: 1;
  background: #EEEEEE;  /* 悬停宣纸灰 - 古籍褪色效果 */
  box-shadow: 0 3px 6px rgba(97, 59, 59, 0.2);  /* 加深投影 - 立体层次 */
}

/* 推理框样式 - 梅韵留白版 */
.mes_reasoning {
  border-left: 3px solid #613B3B;  /* 左侧梅枝棕描边 */
  color: #333333;  /* 墨色文字 - 古籍印刷效果 */
  background: #ffffff;  /* 纯白背景 - 日间模式 */
  /* 背景图放置位置 ↓ */
  /* background-image: url("你的图片链接.jpg"); */
  background-size: cover;
  background-blend-mode: soft-light;
  border-radius: 0 8px 8px 0;
  box-shadow: 0 1px 3px rgba(97, 59, 59, 0.1);  /* 浅棕投影 - 模拟纸张厚度 */
}

/* 标题微调 - 梅枝印记 */
.mes_reasoning_header_title {
  position: relative;
  display: inline-block;
  top: 0px;
  left: -8px;
  color: #613B3B;  /* 梅枝棕标题 - 点睛之笔 */
}
}
}

/* ===== 基础图标样式 ===== */
.drawer-icon:not(.openIcon) { 
  opacity: 0.8 !important; 
}

/* 通用图标替换样式 */
.drawer-icon {
  background: url('https://i.postimg.cc/Dy80Why4/Image-2151109123445292.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
}

.drawer-icon::before {
  display: none !important;
}

/* ===== 特定图标覆盖 ===== */
/* AI响应配置 */
#leftNavDrawerIcon {
  background-image: url('https://i.postimg.cc/Dy80Why4/Image-2151109123445292.png') !important;
}

/* API连接 */
#API-status-top::before { display: none !important; }
#API-status-top {
  background: url('https://i.postimg.cc/76cxyG8H/Image-2152333183881135.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
  font-size: 0 !important;
}

/* AI回复格式化 */
.drawer-icon.fa-font::before { display: none !important; }
.drawer-icon.fa-font {
  background: ur1('https://i.postimg.cc/Dy80Why4/Image-2151109123445292.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
}

/* 世界信息 */
#WIDrawerIcon::before { display: none !important; }
#WIDrawerIcon {
  background: url('https://i.postimg.cc/76cxyG8H/Image-2152333183881135.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
}

/* 用户设置 */
.drawer-icon.fa-user::before { display: none !important; }
.drawer-icon.fa-user {
  background: url('https://i.postimg.cc/Dy80Why4/Image-2151109123445292.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
}

/* 背景更换 */
#site_logo .drawer-icon::before,
#site_logo::before { display: none !important; }
#site_logo .drawer-icon {
  background: url('https://i.postimg.cc/76cxyG8H/Image-2152333183881135.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
}

/* 扩展功能 */
.drawer-icon.fa-cubes::before { display: none !important; }
.drawer-icon.fa-cubes {
  background: url('https://i.postimg.cc/Dy80Why4/Image-2151109123445292.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
}

/* 事件表 */
#table_drawer_icon::before { display: none !important; }
#table_drawer_icon {
  background: url('https://i.postimg.cc/76cxyG8H/Image-2152333183881135.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
}

/* 用户角色管理 */
